const redeemRewardPointsSimple = `-- name: RedeemRewardPointsSimple :one
WITH updated_user AS (
    UPDATE users
    SET reward_balance = reward_balance - $2,
        total_reward_redeemed = total_reward_redeemed + $2,
        updated_at = NOW()
    WHERE id = $1
      AND reward_balance >= $2
    RETURNING reward_balance
)
INSERT INTO reward_transactions (
    user_id,
    transaction_id,
    transaction_type,
    source_transaction_type,
    transaction_amount,
    points_amount,
    naira_value,
    description,
    status,
    balance_after
)
SELECT 
    $1, -- user_id
    $3, -- transaction_id
    'redeemed',
    'bill_payment',
    $4, -- transaction_amount
    $2, -- points_amount
    $2, -- naira_value (1:1 ratio)
    $5, -- description
    'completed',
    updated_user.reward_balance
FROM updated_user
RETURNING id, user_id, transaction_id, transaction_type, source_transaction_type, transaction_amount, points_amount, naira_value, reward_config_id, description, status, balance_after, metadata, created_at, updated_at
`

type RedeemRewardPointsSimpleParams struct {
	UserID            int64          `json:"user_id"`
	PointsAmount      string         `json:"points_amount"`
	TransactionID     uuid.NullUUID  `json:"transaction_id"`
	TransactionAmount sql.NullString `json:"transaction_amount"`
	Description       sql.NullString `json:"description"`
}

// Redeem reward points (deduct from balance)
// This should be called within a transaction
func (q *Queries) RedeemRewardPointsSimple(ctx context.Context, arg RedeemRewardPointsSimpleParams) (RewardTransaction, error) {
	row := q.db.QueryRowContext(ctx, redeemRewardPointsSimple,
		arg.UserID,
		arg.PointsAmount,
		arg.TransactionID,
		arg.TransactionAmount,
		arg.Description,
	)
	var i RewardTransaction
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.TransactionID,
		&i.TransactionType,
		&i.SourceTransactionType,
		&i.TransactionAmount,
		&i.PointsAmount,
		&i.NairaValue,
		&i.RewardConfigID,
		&i.Description,
		&i.Status,
		&i.BalanceAfter,
		&i.Metadata,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

